#include <vector>
#include <algorithm>
#include <iostream>

using namespace std;

long long solve(std::vector<long long> nums, long long k) {
    int n = nums.size();

    // Precompute prefix maximums: prefix_max[i] = max(nums[0..i])
    std::vector<long long> prefix_max(n);
    prefix_max[0] = nums[0];
    for (int i = 1; i < n; ++i) {
        prefix_max[i] = std::max(prefix_max[i-1], nums[i]);
    }

    // Precompute suffix minimums: suffix_min[i] = min(nums[i..n-1])
    std::vector<long long> suffix_min(n);
    suffix_min[n-1] = nums[n-1];
    for (int i = n - 2; i >= 0; --i) {
        suffix_min[i] = std::min(suffix_min[i+1], nums[i]);
    }

    // Iterate through all indices i and check the instability value
    for (int i = 0; i < n; ++i) {
        // Unstable value for index i: max(nums[0..i]) - min(nums[i..n-1])
        long long unstable_value = prefix_max[i] - suffix_min[i];

        // Check if the index i is stable
        if (unstable_value <= k) {
            return i; // Return the smallest stable index
        }
    }

    // If no stable index is found
    return -1;
}

